let rec dump_each = fun toks -> if is_empty toks then () else let t = hd toks in let _ = (match t with (0, (_, s)) -> print_endline ("IDENT  " ^ s) | (1, (n, _)) -> print_endline ("INT    " ^ string_of_int n) | (2, (p, _)) -> print_endline ("PCT    " ^ string_of_int p) | (3, (_, _)) -> print_endline "LARROW" | (4, (_, _)) -> print_endline "RARROW" | (5, (_, _)) -> print_endline "LPAREN" | (6, (_, _)) -> print_endline "RPAREN" | (7, (_, _)) -> print_endline "LBRACE" | (8, (_, _)) -> print_endline "RBRACE" | (9, (_, _)) -> print_endline "COMMA" | (10, (_, _)) -> print_endline "USCORE" | (11, (_, s)) -> print_endline ("HASH   " ^ s) | (12, (_, s)) -> print_endline ("LIT    " ^ s) | (13, (_, _)) -> print_endline "EOF" | (14, (_, _)) -> print_endline "MINT" | (_, (_, _)) -> print_endline "?") in dump_each (tl toks) in dump_each [(14, (0, "")); (0, (0, "coord2")); (4, (0, "")); (5, (0, "")); (0, (0, "x")); (0, (0, "y")); (6, (0, "")); (3, (0, "")); (1, (3, "")); (9, (0, "")); (1, (9, "")); (12, (0, "if")); (10, (0, "")); (11, (0, "comment text")); (13, (0, ""))]
